    ```java
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Vector;

public class Solution {
    static final int MOD = 1000000007;

    public static ArrayList<Integer> productWays(int[][] queries) {
        ArrayList<Integer> res = new ArrayList<>();
        for (int[] q : queries) {
            int n = q[0], k = q[1];

            List<Integer> pf = new ArrayList<>();
            Map<Integer, Integer> pm = new HashMap<>();
            for (int i = 2; i * i <= k; ++i) {
                int cnt = 0;
                while (k % i == 0) {
                    cnt++;
                    k /= i;
                }
                if (cnt != 0) {
                    pf.add(cnt);
                    pm.put(cnt, pm.getOrDefault(cnt, 0) + 1);
                }
            }

            if (k > 1) {
                pm.put(k, pm.getOrDefault(k, 0) + 1);
                pf.add(1);
            }

            long ans = 1;
            for (int p : pf) {
                ans = (ans * (p * (n - 1) + 1)) % MOD;
            }

            res.add((int) ans);
        }
        return res;
    }
}
```

    1. For each query, find the prime factors of number k.
2. Store the counts of each prime factor in an array and a map.
3. Initialize the answer for the current query to 1.
4. Iterate through the array of prime factor counts and multiply the answer with the result of each count multiplied by n-1 and added 1. Take the modulo (1e9 + 7) in each step.
5. Append the answer for the current query to the result list and return the result list.
